// Validate inputs
const body = $input.first().json.body;
const token = body.token;
const phone = body.telegramPhone;
const chatId = body.telegramChatId;

if (!token) throw new Error('JWT token is required');
if (!phone || !/^\+?[0-9]{7,15}$/.test(phone)) {
  throw new Error('Invalid phone number. Must be 7-15 digits, optional leading +');
}
if (!chatId || !/^[0-9]{5,15}$/.test(String(chatId).trim())) {
  throw new Error('Invalid chat ID. Must be a numeric ID from @userinfobot.');
}

return [{ json: { token, telegramPhone: phone, telegramChatId: String(chatId).trim() } }];

// Check Node.js response
const response = $input.first().json;
if (!response.success) {
  throw new Error('Node.js API error: ' + (response.message || 'Unknown'));
}
return [{ json: {
  telegramPhone: $('Validate Input').first().json.telegramPhone,
  telegramChatId: $('Validate Input').first().json.telegramChatId,
  savedOk: true
}}];
